/// MAINFILE
fn p_mainfile(state: &mut ProgramState) {
    println!();
    println!();
    // SKIP: unresolved display ref
    println!("{}{}{}", "File has ", state.key_def.key_nkeys, " keys.");
    println!("{}{}{}", "Key def  ", state.key_def.kdb_len, " bytes.");
    println!();
    // SKIP: unresolved display ref
    // SKIP: unresolved ref: state._unresolved_fcd_filename_address = &state._unresolved_out_file_name as *const _ as usize;
    // SKIP: unresolved ref: state._unresolved_fcd_name_length = std::mem::size_of_val(&state._unresolved_out_file_name) as i64;
    println!("{}", "*** Dump FCD before changes");
    p_dump_fcd(state);
    state.key_def.key_defs[((2 - 1) as usize).min(0)].key_flags = FixedString::from_str("64");
    state.key_def.key_defs[((3 - 1) as usize).min(0)].key_flags = FixedString::from_str("66");
    state.key_def.key_defs[((3 - 1) as usize).min(0)].key_sparse = "*".into();
    println!("{}", "*** Dump FCD after changes");
    p_dump_fcd(state);
    p_loadfile(state);
    p_listfile(state);
    { let _ = state._fh_tspfile.close();
        std::process::exit(0); }
}

