/// LOADFILE
fn p_loadfile(state: &mut ProgramState) {
    tspfile_open_output(state);
    println!();
    // SKIP: unresolved display ref
    if ({ let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "00".to_string()) && ({ let _s = format!("{}", state.cust_stat); _s.trim().to_string() } != "05".to_string()) {
        // SKIP: unresolved display ref
        { let _ = state._fh_tspfile.close();
            std::process::exit(0); }
    }
    p_1000_load_record(state);
}

